package policy

import (
	"context"
	"fmt"

	"github.com/sirupsen/logrus"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/lock"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

var log = logging.DefaultLogger.WithField(logfields.LogSubsys, "policy")

// PolicyAuditLogger provides structured logging of policy evaluation decisions
// for audit and debugging purposes.
type PolicyAuditLogger struct {
	lock.Mutex

	// logger is the logrus logger instance for audit logging
	logger logrus.FieldLogger

	// logLevel controls the minimum log level for audit events
	logLevel logrus.Level
}

// NewPolicyAuditLogger creates a new PolicyAuditLogger with the specified
// log level and output configuration.
func NewPolicyAuditLogger(logger logrus.FieldLogger, logLevel logrus.Level) *PolicyAuditLogger {
	if logger == nil {
		logger = log
	}
	return &PolicyAuditLogger{
		logger:   logger,
		logLevel: logLevel,
	}
}

// LogDecision logs a policy decision for an identity-policy pair with a verdict
// and reason. This is used for audit and debugging of policy evaluation.
func (pal *PolicyAuditLogger) LogDecision(
	identity identity.NumericIdentity,
	policy string,
	verdict string,
	reason string,
) {
	pal.Lock()
	defer pal.Unlock()

	fields := logrus.Fields{
		logfields.Identity: identity,
		"policy":           policy,
		"verdict":          verdict,
		"reason":           reason,
	}

	entry := pal.logger.WithFields(fields)
	switch pal.logLevel {
	case logrus.DebugLevel:
		entry.Debug("Policy decision logged")
	case logrus.InfoLevel:
		entry.Info("Policy decision logged")
	case logrus.WarnLevel:
		entry.Warn("Policy decision logged")
	case logrus.ErrorLevel:
		entry.Error("Policy decision logged")
	default:
		entry.WithField("logLevel", pal.logLevel).Debug("Policy decision logged")
	}
}

// LogEvaluation logs a complete policy evaluation result including the policy key,
// selector cache state, and the evaluation result.
func (pal *PolicyAuditLogger) LogEvaluation(
	ctx context.Context,
	policyKey string,
	selectorCache *SelectorCache,
	result interface{},
) {
	pal.Lock()
	defer pal.Unlock()

	fields := logrus.Fields{
		logfields.PolicyKey: policyKey,
		"result":            fmt.Sprintf("%+v", result),
	}

	if selectorCache != nil {
		fields["selectorCacheSize"] = len(selectorCache.GetModel())
	}

	entry := pal.logger.WithFields(fields)
	switch pal.logLevel {
	case logrus.DebugLevel:
		entry.Debug("Policy evaluation logged")
	case logrus.InfoLevel:
		entry.Info("Policy evaluation logged")
	case logrus.WarnLevel:
		entry.Warn("Policy evaluation logged")
	case logrus.ErrorLevel:
		entry.Error("Policy evaluation logged")
	default:
		entry.WithField("logLevel", pal.logLevel).Debug("Policy evaluation logged")
	}
}

// SetLogLevel updates the log level for the audit logger.
func (pal *PolicyAuditLogger) SetLogLevel(level logrus.Level) {
	pal.Lock()
	defer pal.Unlock()
	pal.logLevel = level
}

// GetLogLevel returns the current log level.
func (pal *PolicyAuditLogger) GetLogLevel() logrus.Level {
	pal.Lock()
	defer pal.Unlock()
	return pal.logLevel
}

