package policy

import (
	"context"
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
)

func TestNewPolicyAuditLogger(t *testing.T) {
	logger := NewPolicyAuditLogger(nil, logrus.InfoLevel)
	require.NotNil(t, logger)
	require.Equal(t, logrus.InfoLevel, logger.GetLogLevel())
}

func TestNewPolicyAuditLoggerWithCustomLogger(t *testing.T) {
	customLogger := logrus.New()
	logger := NewPolicyAuditLogger(customLogger, logrus.DebugLevel)
	require.NotNil(t, logger)
	require.Equal(t, logrus.DebugLevel, logger.GetLogLevel())
}

func TestLogDecision(t *testing.T) {
	logger := NewPolicyAuditLogger(nil, logrus.InfoLevel)

	// Test basic LogDecision call
	id := identity.NumericIdentity(1234)
	logger.LogDecision(id, "test-policy", "allow", "matched selector")
	// No panic should occur

	// Test with different verdict
	logger.LogDecision(id, "test-policy", "deny", "denied by rule")
	// No panic should occur
}

func TestLogDecisionWithDifferentLogLevels(t *testing.T) {
	levels := []logrus.Level{
		logrus.DebugLevel,
		logrus.InfoLevel,
		logrus.WarnLevel,
		logrus.ErrorLevel,
	}

	for _, level := range levels {
		t.Run(level.String(), func(t *testing.T) {
			logger := NewPolicyAuditLogger(nil, level)
			id := identity.NumericIdentity(5678)

			// Should not panic for any log level
			logger.LogDecision(id, "policy-name", "verdict", "reason")
		})
	}
}

func TestLogEvaluation(t *testing.T) {
	logger := NewPolicyAuditLogger(nil, logrus.InfoLevel)
	ctx := context.Background()

	// Test with nil SelectorCache
	logger.LogEvaluation(ctx, "policy-key-1", nil, map[string]interface{}{"result": "allowed"})
	// No panic should occur

	// Test with context
	ctx2, cancel := context.WithCancel(context.Background())
	defer cancel()
	logger.LogEvaluation(ctx2, "policy-key-2", nil, "allow")
	// No panic should occur
}

func TestLogEvaluationWithSelectorCache(t *testing.T) {
	logger := NewPolicyAuditLogger(nil, logrus.InfoLevel)
	ctx := context.Background()

	// Create a selector cache
	repo := NewPolicyRepository()
	selectorCache := repo.GetSelectorCache()

	logger.LogEvaluation(ctx, "test-policy-key", selectorCache, map[string]string{"verdict": "allow"})
	// No panic should occur
}

func TestSetLogLevel(t *testing.T) {
	logger := NewPolicyAuditLogger(nil, logrus.InfoLevel)
	require.Equal(t, logrus.InfoLevel, logger.GetLogLevel())

	logger.SetLogLevel(logrus.DebugLevel)
	require.Equal(t, logrus.DebugLevel, logger.GetLogLevel())

	logger.SetLogLevel(logrus.WarnLevel)
	require.Equal(t, logrus.WarnLevel, logger.GetLogLevel())
}

func TestThreadSafety(t *testing.T) {
	logger := NewPolicyAuditLogger(nil, logrus.InfoLevel)

	// Run concurrent operations
	done := make(chan bool, 10)

	// Concurrent LogDecision calls
	for i := 0; i < 5; i++ {
		go func(idx int) {
			id := identity.NumericIdentity(1000 + idx)
			logger.LogDecision(id, "policy-name", "allow", "test")
			done <- true
		}(i)
	}

	// Concurrent LogEvaluation calls
	for i := 0; i < 5; i++ {
		go func(idx int) {
			logger.LogEvaluation(context.Background(), "policy-key", nil, "result")
			done <- true
		}(i)
	}

	// Wait for all goroutines
	for i := 0; i < 10; i++ {
		<-done
	}
}

func TestThreadSafetyWithLogLevelChanges(t *testing.T) {
	logger := NewPolicyAuditLogger(nil, logrus.InfoLevel)

	done := make(chan bool, 6)

	// Concurrent logging operations
	for i := 0; i < 3; i++ {
		go func() {
			logger.LogDecision(identity.NumericIdentity(1), "policy", "allow", "test")
			done <- true
		}()
	}

	// Concurrent log level changes
	for i := 0; i < 3; i++ {
		go func(idx int) {
			levels := []logrus.Level{
				logrus.DebugLevel,
				logrus.InfoLevel,
				logrus.WarnLevel,
			}
			logger.SetLogLevel(levels[idx])
			done <- true
		}(i)
	}

	// Wait for all goroutines
	for i := 0; i < 6; i++ {
		<-done
	}
}

func TestLogDecisionWithVaryingParameters(t *testing.T) {
	logger := NewPolicyAuditLogger(nil, logrus.DebugLevel)

	testCases := []struct {
		name     string
		identity identity.NumericIdentity
		policy   string
		verdict  string
		reason   string
	}{
		{
			name:     "allow verdict",
			identity: identity.NumericIdentity(100),
			policy:   "allow-all",
			verdict:  "allow",
			reason:   "matched allow rule",
		},
		{
			name:     "deny verdict",
			identity: identity.NumericIdentity(200),
			policy:   "deny-all",
			verdict:  "deny",
			reason:   "matched deny rule",
		},
		{
			name:     "default verdict",
			identity: identity.NumericIdentity(300),
			policy:   "default-policy",
			verdict:  "default",
			reason:   "no matching rule",
		},
		{
			name:     "large identity",
			identity: identity.NumericIdentity(999999),
			policy:   "test-policy",
			verdict:  "allow",
			reason:   "test reason",
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			logger.LogDecision(tc.identity, tc.policy, tc.verdict, tc.reason)
			// No panic should occur
		})
	}
}

func TestLogEvaluationWithVaryingResults(t *testing.T) {
	logger := NewPolicyAuditLogger(nil, logrus.DebugLevel)
	ctx := context.Background()

	testCases := []struct {
		name      string
		policyKey string
		result    interface{}
	}{
		{
			name:      "string result",
			policyKey: "policy-1",
			result:    "allow",
		},
		{
			name:      "map result",
			policyKey: "policy-2",
			result:    map[string]interface{}{"status": "allowed", "rules": []string{"r1", "r2"}},
		},
		{
			name:      "struct result",
			policyKey: "policy-3",
			result:    struct{ Allowed bool }{Allowed: true},
		},
		{
			name:      "slice result",
			policyKey: "policy-4",
			result:    []string{"allow", "rule1", "rule2"},
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			logger.LogEvaluation(ctx, tc.policyKey, nil, tc.result)
			// No panic should occur
		})
	}
}

